svg.script:
var seed = 77;
function rand() { seed = (seed * 16807 + 0) % 2147483647; return (seed - 1) / 2147483646; }
function noise() { return (rand() - 0.5) * 2; }

var W = 720, H = 230, OX = 50, OY = 20;
var midY = OY + H / 2;
var totalTime = 15;
var samplesPerSec = 50;
var totalSamples = totalTime * samplesPerSec;

// TUG phases:
// 0-2s: rest
// 2-3.5s: stand up (burst)
// 3.5-6.5s: walking to marker (~1.8Hz rhythmic)
// 6.5-8.0s: turn (irregular)
// 8.0-11.0s: walking back (~1.8Hz)
// 11.0-12.5s: sit down (burst)
// 12.5-15s: rest

function getPhase(t) {
  if (t < 2.0) return {type: 'rest', env: 0};
  if (t < 3.5) {
    var f = (t - 2.0) / 1.5;
    var env = f < 0.5 ? Math.sin(f * Math.PI) * 1.2 : Math.sin(f * Math.PI) * 0.8;
    return {type: 'stand', env: Math.min(env, 1.0)};
  }
  if (t < 6.5) {
    var f = (t - 3.5) / 3.0;
    // Ramp up at start
    var ramp = Math.min(f * 4, 1.0);
    return {type: 'walk', env: 0.7 * ramp};
  }
  if (t < 8.0) {
    return {type: 'turn', env: 0.4};
  }
  if (t < 11.0) {
    var f = (t - 8.0) / 3.0;
    var ramp = Math.min((1 - f) * 4, 1.0) * Math.min(f * 4, 1.0);
    return {type: 'walk', env: 0.7 * Math.max(ramp, 0.3)};
  }
  if (t < 12.5) {
    var f = (t - 11.0) / 1.5;
    var env = Math.sin(f * Math.PI) * 1.0;
    return {type: 'sit', env: Math.min(env, 1.0)};
  }
  return {type: 'rest', env: 0};
}

function genSignal(ampScale, freqWalk, phaseOff, noiseBase) {
  var pts = [];
  for (var i = 0; i < totalSamples; i++) {
    var t = i / samplesPerSec;
    var ph = getPhase(t);
    var val = 0;

    if (ph.type === 'rest') {
      val = 0.015 * Math.sin(2 * Math.PI * 0.1 * t + phaseOff) + noise() * 0.008;
    } else if (ph.type === 'stand' || ph.type === 'sit') {
      val = ph.env * ampScale * 0.35 * (
        Math.sin(2 * Math.PI * 1.2 * t + phaseOff) * 0.5 +
        Math.sin(2 * Math.PI * 2.8 * t + phaseOff * 1.3) * 0.3 +
        Math.sin(2 * Math.PI * 4.5 * t + phaseOff * 0.7) * 0.2
      ) + noise() * noiseBase * 2 * ph.env;
    } else if (ph.type === 'walk') {
      val = ph.env * ampScale * 0.25 * (
        Math.sin(2 * Math.PI * freqWalk * t + phaseOff) * 0.7 +
        Math.sin(2 * Math.PI * freqWalk * 2 * t + phaseOff * 0.8) * 0.2 +
        Math.sin(2 * Math.PI * freqWalk * 0.5 * t + phaseOff * 1.5) * 0.1
      ) + noise() * noiseBase * 0.8 * ph.env;
    } else if (ph.type === 'turn') {
      val = ph.env * ampScale * 0.18 * (
        Math.sin(2 * Math.PI * 1.1 * t + phaseOff) * 0.4 +
        Math.sin(2 * Math.PI * 2.3 * t + phaseOff * 2.1) * 0.3 +
        Math.sin(2 * Math.PI * 3.7 * t + phaseOff * 0.6) * 0.3
      ) + noise() * noiseBase * 1.5 * ph.env;
    }
    pts.push(val);
  }
  return pts;
}

var xSig = genSignal(1.0, 1.8, 0, 0.02);
var ySig = genSignal(0.6, 1.8, 1.8, 0.015);
var zSig = genSignal(0.9, 1.8, 3.5, 0.018);

function toPath(sig) {
  var maxAmp = 0.4;
  var d = "";
  for (var i = 0; i < sig.length; i++) {
    var x = OX + (i / totalSamples) * W;
    var y = midY - (sig[i] / maxAmp) * (H / 2 - 10);
    d += (i === 0 ? "M" : "L") + x.toFixed(1) + "," + y.toFixed(1);
  }
  return d;
}

document.getElementById("pathX").setAttribute("d", toPath(xSig));
document.getElementById("pathY").setAttribute("d", toPath(ySig));
document.getElementById("pathZ").setAttribute("d", toPath(zSig));
